css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { min-height: 100vh; background: linear-gradient(160deg, #052e16 0%, #0a3d20 50%, #030a03 100%); font-family: -apple-system, BlinkMacSystemFont, sans-serif; display: flex; align-items: center; justify-content: center; padding: 20px; color: white; }
.app { width: 100%; max-width: 460px; }
h1 { font-size: 28px; font-weight: 900; text-align: center; margin-bottom: 6px; }
.subtitle { text-align: center; color: rgba(255,255,255,0.5); font-size: 14px; margin-bottom: 28px; }
.converter { background: rgba(255,255,255,0.07); border: 1px solid rgba(255,255,255,0.12); border-radius: 24px; padding: 24px; margin-bottom: 16px; }
.input-group { margin-bottom: 16px; }
.input-group label { display: block; font-size: 12px; font-weight: 700; color: rgba(255,255,255,0.5); letter-spacing: 1px; margin-bottom: 8px; }
.input-wrap input { width: 100%; height: 56px; border-radius: 14px; border: 1px solid rgba(255,255,255,0.15); background: rgba(255,255,255,0.08); color: white; padding: 0 18px; font-size: 24px; font-weight: 700; outline: none; transition: border-color 0.2s; } input:focus { border-color: #22c55e; }
.currency-row { display: flex; align-items: flex-end; gap: 12px; margin-bottom: 20px; }
.currency-select { flex: 1; } .currency-select label { display: block; font-size: 12px; font-weight: 700; color: rgba(255,255,255,0.5); letter-spacing: 1px; margin-bottom: 8px; }
.currency-select select { width: 100%; height: 52px; border-radius: 14px; border: 1px solid rgba(255,255,255,0.15); background: rgba(255,255,255,0.08); color: white; padding: 0 14px; font-size: 16px; font-weight: 600; outline: none; cursor: pointer; }
.swap-btn { width: 48px; height: 52px; border-radius: 14px; border: 1px solid rgba(255,255,255,0.15); background: rgba(255,255,255,0.08); color: white; font-size: 20px; cursor: pointer; transition: all 0.2s; flex-shrink: 0; } .swap-btn:hover { background: rgba(34,197,94,0.2); border-color: #22c55e; }
.result-card { background: rgba(34,197,94,0.1); border: 1px solid rgba(34,197,94,0.3); border-radius: 16px; padding: 20px; text-align: center; }
.result-amount { font-size: 42px; font-weight: 900; color: #22c55e; margin-bottom: 6px; }
.result-rate { font-size: 14px; color: rgba(255,255,255,0.5); }
.quick-amounts { display: flex; align-items: center; gap: 10px; margin-bottom: 20px; flex-wrap: wrap; }
.quick-amounts span { font-size: 13px; color: rgba(255,255,255,0.5); }
.quick-amounts button { padding: 8px 16px; border-radius: 20px; border: 1px solid rgba(255,255,255,0.15); background: rgba(255,255,255,0.06); color: white; font-size: 13px; font-weight: 600; cursor: pointer; transition: all 0.2s; } .quick-amounts button:hover { background: rgba(34,197,94,0.15); border-color: #22c55e; }
.rates-grid { background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); border-radius: 20px; padding: 20px; }
.rates-grid h3 { font-size: 15px; font-weight: 700; margin-bottom: 16px; display: flex; align-items: center; gap: 10px; }
.live-badge { color: #22c55e; font-size: 12px; font-weight: 600; }
.rates { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }
.rate-item { background: rgba(255,255,255,0.04); border-radius: 12px; padding: 12px; display: flex; justify-content: space-between; align-items: center; }
.rate-pair { font-size: 13px; font-weight: 700; color: rgba(255,255,255,0.7); }
.rate-value { font-size: 14px; font-weight: 800; color: #22c55e; }

js:
const currencies = { USD: { name: 'Dolar', flag: '🇺🇸', rate: 1 }, EUR: { name: 'Euro', flag: '🇪🇺', rate: 0.92 }, TRY: { name: 'Türk Lirası', flag: '🇹🇷', rate: 32.5 }, GBP: { name: 'Sterlin', flag: '🇬🇧', rate: 0.79 }, JPY: { name: 'Japon Yeni', flag: '🇯🇵', rate: 149.5 }, CHF: { name: 'İsviçre Frangı', flag: '🇨🇭', rate: 0.88 }, CAD: { name: 'Kanada Doları', flag: '🇨🇦', rate: 1.36 }, AUD: { name: 'Avustralya Doları', flag: '🇦🇺', rate: 1.53 } };
const popularPairs = [['USD','TRY'],['EUR','TRY'],['GBP','TRY'],['USD','EUR']];
function populate() {
  ['from','to'].forEach(id => {
    const sel = document.getElementById(id);
    Object.entries(currencies).forEach(([code, info]) => {
      const opt = document.createElement('option');
      opt.value = code;
      opt.textContent = info.flag + ' ' + code + ' - ' + info.name;
      sel.appendChild(opt);
    });
  });
  document.getElementById('from').value = 'USD';
  document.getElementById('to').value = 'TRY';
}
function convert() {
  const amount = parseFloat(document.getElementById('amount').value) || 0;
  const from = document.getElementById('from').value;
  const to = document.getElementById('to').value;
  const usdAmount = amount / currencies[from].rate;
  const result = usdAmount * currencies[to].rate;
  const rate = currencies[to].rate / currencies[from].rate;
  document.getElementById('result').textContent = result.toFixed(2) + ' ' + to;
  document.getElementById('rate').textContent = '1 ' + from + ' = ' + rate.toFixed(4) + ' ' + to;
}
function swap() {
  const from = document.getElementById('from').value;
  const to = document.getElementById('to').value;
  document.getElementById('from').value = to;
  document.getElementById('to').value = from;
  convert();
}
function setAmount(n) { document.getElementById('amount').value = n; convert(); }
function renderRates() {
  document.getElementById('rates').innerHTML = popularPairs.map(([a,b]) => {
    const rate = (currencies[b].rate / currencies[a].rate).toFixed(4);
    return `<div class='rate-item'><span class='rate-pair'>${a}/${b}</span><span class='rate-value'>${rate}</span></div>`;
  }).join('');
}
populate(); convert(); renderRates();
